```cpp
// llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
bool HorizontalReduction::tryToReduce(...) {
...
  // Reorder the scalars to match the reduction order.
  if (Rdx->isOrdered()) {
    SmallVector<unsigned, 16> Order;
    Rdx->getReductionOrder(Order);
    Builder.setHorRdxOrder(Order);
  }
...
